-- Schema: stock
CREATE SCHEMA IF NOT EXISTS stock;

CREATE OR REPLACE FUNCTION stock._recalc_pmp(p_article_id integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_total_qty numeric := 0;
  v_total_val numeric := 0;
  r record;
BEGIN
  -- Parcourir les entrées chronologiquement pour recalculer le PMP
  FOR r IN
    SELECT quantite, prix_unitaire
    FROM stock.mouvement
    WHERE article_id = p_article_id AND type = 'entree'
    ORDER BY created_at
  LOOP
    v_total_val := v_total_val + (r.quantite * coalesce(r.prix_unitaire, 0));
    v_total_qty := v_total_qty + r.quantite;
  END LOOP;

  UPDATE stock.article
  SET pmp = CASE WHEN v_total_qty > 0 THEN v_total_val / v_total_qty ELSE 0 END
  WHERE id = p_article_id;
END;
$function$;
COMMENT ON FUNCTION stock._recalc_pmp(integer) IS 'Recalcule le PMP (prix moyen pondéré) d''un article à partir de toutes les entrées';

CREATE OR REPLACE FUNCTION stock._set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at := clock_timestamp();
  RETURN NEW;
END;
$function$;
COMMENT ON FUNCTION stock._set_updated_at() IS 'Trigger: set updated_at to clock_timestamp() on UPDATE';

CREATE OR REPLACE FUNCTION stock._stock_actuel(p_article_id integer, p_depot_id integer DEFAULT NULL::integer)
 RETURNS numeric
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_qty numeric;
BEGIN
  IF p_depot_id IS NOT NULL THEN
    SELECT coalesce(sum(quantite), 0) INTO v_qty
    FROM stock.mouvement
    WHERE article_id = p_article_id AND depot_id = p_depot_id;
  ELSE
    SELECT coalesce(sum(quantite), 0) INTO v_qty
    FROM stock.mouvement
    WHERE article_id = p_article_id;
  END IF;
  RETURN v_qty;
END;
$function$;
COMMENT ON FUNCTION stock._stock_actuel(integer,integer) IS 'Calcule le stock actuel d''un article (tous dépôts ou un dépôt spécifique)';

CREATE OR REPLACE FUNCTION stock.article_options(p_search text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN coalesce((
    SELECT jsonb_agg(row_to_json(r)::jsonb)
    FROM (
      SELECT
        a.id::text AS value,
        a.designation AS label,
        a.reference || ' — ' || a.categorie || ' (' || a.unite || ')' AS detail
      FROM stock.article a
      WHERE a.active
        AND (p_search IS NULL OR p_search = ''
          OR a.designation ILIKE '%' || p_search || '%'
          OR a.reference ILIKE '%' || p_search || '%')
      ORDER BY a.designation
      LIMIT 20
    ) r
  ), '[]'::jsonb);
END;
$function$;
COMMENT ON FUNCTION stock.article_options(text) IS 'Search articles for pgv.select_search() — returns jsonb array {value, label, detail}';

