CREATE OR REPLACE FUNCTION stock.entree_reception(p_data jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
-- p_data: {
--   "reception_ref": "REC-2026-001",  -- reference pour traçabilité
--   "depot_id": 1,                     -- dépôt destination
--   "lignes": [
--     {"article_id": 1, "quantite": 10, "prix_unitaire": 5.50},
--     ...
--   ]
-- }
DECLARE
  v_depot_id int := (p_data->>'depot_id')::int;
  v_ref text := coalesce(p_data->>'reception_ref', 'RECEPTION');
  v_lignes jsonb := p_data->'lignes';
  v_ligne jsonb;
  v_article_id int;
  v_quantite numeric;
  v_prix numeric;
  v_nb_articles int := 0;
  v_total_qty numeric := 0;
  v_total_valeur numeric := 0;
BEGIN
  -- Valider le dépôt
  IF NOT EXISTS (SELECT 1 FROM stock.depot WHERE id = v_depot_id AND actif) THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Dépôt inexistant ou inactif');
  END IF;

  IF v_lignes IS NULL OR jsonb_array_length(v_lignes) = 0 THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Aucune ligne à réceptionner');
  END IF;

  FOR i IN 0 .. jsonb_array_length(v_lignes) - 1 LOOP
    v_ligne := v_lignes->i;
    v_article_id := (v_ligne->>'article_id')::int;
    v_quantite := (v_ligne->>'quantite')::numeric;
    v_prix := (v_ligne->>'prix_unitaire')::numeric;

    -- Valider l'article
    IF NOT EXISTS (SELECT 1 FROM stock.article WHERE id = v_article_id AND active) THEN
      CONTINUE; -- skip articles inconnus
    END IF;

    IF v_quantite IS NULL OR v_quantite <= 0 THEN
      CONTINUE;
    END IF;

    -- Créer mouvement entree
    INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference)
    VALUES (v_article_id, v_depot_id, 'entree', v_quantite, v_prix, v_ref);

    -- Recalculer PMP
    PERFORM stock._recalc_pmp(v_article_id);

    -- Mettre à jour prix_achat si fourni
    IF v_prix IS NOT NULL THEN
      UPDATE stock.article SET prix_achat = v_prix WHERE id = v_article_id;
    END IF;

    v_nb_articles := v_nb_articles + 1;
    v_total_qty := v_total_qty + v_quantite;
    v_total_valeur := v_total_valeur + coalesce(v_quantite * v_prix, 0);
  END LOOP;

  RETURN jsonb_build_object(
    'ok', true,
    'nb_articles', v_nb_articles,
    'total_quantite', v_total_qty,
    'total_valeur', round(v_total_valeur, 2),
    'depot_id', v_depot_id,
    'reference', v_ref
  );
END;
$function$;
COMMENT ON FUNCTION stock.entree_reception(jsonb) IS 'Create stock entry movements from a purchase reception. Called cross-module by purchase.';

CREATE OR REPLACE FUNCTION stock.get_alertes()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  r record;
  v_qty numeric;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.id, a.reference, a.designation, a.unite, a.seuil_mini, a.fournisseur_id,
           c.name AS fournisseur
    FROM stock.article a
    LEFT JOIN crm.client c ON c.id = a.fournisseur_id
    WHERE a.active AND a.seuil_mini > 0
    ORDER BY a.designation
  LOOP
    v_qty := stock._stock_actuel(r.id);
    IF v_qty < r.seuil_mini THEN
      v_rows := v_rows || ARRAY[
        format('<a href="%s">%s</a>', pgv.call_ref('get_article', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
        pgv.esc(r.designation),
        v_qty::text || ' ' || r.unite,
        r.seuil_mini::text || ' ' || r.unite,
        pgv.badge('ALERTE', 'danger'),
        CASE WHEN r.fournisseur IS NOT NULL
          THEN format('<a href="/crm/client?p_id=%s">%s</a>', r.fournisseur_id, pgv.esc(r.fournisseur))
          ELSE '—'
        END
      ];
    END IF;
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty('Aucune alerte', 'Tous les articles sont au-dessus du seuil minimum.');
  ELSE
    v_body := pgv.md_table(
      ARRAY['Réf.', 'Désignation', 'Stock', 'Seuil', 'Statut', 'Fournisseur'],
      v_rows
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_alertes() IS 'Articles sous seuil minimum d''alerte, lien fournisseur CRM';

CREATE OR REPLACE FUNCTION stock.get_article(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_art stock.article;
  v_body text;
  v_rows text[];
  v_fournisseur text;
  v_fournisseur_link text;
  v_stock_total numeric;
  v_catalog_link text;
  r record;
BEGIN
  SELECT * INTO v_art FROM stock.article WHERE id = p_id;
  IF NOT FOUND THEN RETURN pgv.empty('Article introuvable', ''); END IF;

  SELECT name INTO v_fournisseur FROM crm.client WHERE id = v_art.fournisseur_id;
  v_stock_total := stock._stock_actuel(p_id);

  -- Fournisseur avec lien CRM
  IF v_fournisseur IS NOT NULL THEN
    v_fournisseur_link := format('<a href="/crm/client?p_id=%s">%s</a>', v_art.fournisseur_id, pgv.esc(v_fournisseur));
  ELSE
    v_fournisseur_link := '—';
  END IF;

  -- Lien catalog (cross-module, guard pg_proc)
  v_catalog_link := '—';
  IF v_art.catalog_article_id IS NOT NULL
    AND EXISTS (SELECT 1 FROM pg_namespace WHERE nspname = 'catalog')
    AND EXISTS (SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace WHERE n.nspname = 'catalog' AND p.proname = 'get_article')
  THEN
    v_catalog_link := format('<a href="/catalog/article?p_id=%s">Voir fiche catalog</a>', v_art.catalog_article_id);
  ELSIF v_art.catalog_article_id IS NOT NULL THEN
    v_catalog_link := format('#%s (catalog non disponible)', v_art.catalog_article_id);
  END IF;

  -- Header stats
  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Stock total', v_stock_total::text || ' ' || v_art.unite),
    pgv.stat('PMP', CASE WHEN v_art.pmp > 0 THEN to_char(v_art.pmp, 'FM999G990D00') || ' EUR' ELSE '—' END),
    pgv.stat('Seuil mini', CASE WHEN v_art.seuil_mini > 0 THEN v_art.seuil_mini::text || ' ' || v_art.unite ELSE '—' END),
    pgv.stat('Fournisseur', v_fournisseur_link)
  ]);

  -- Info
  v_body := v_body || format('<p><strong>Réf:</strong> %s | <strong>Catégorie:</strong> %s | <strong>Actif:</strong> %s</p>',
    pgv.esc(v_art.reference),
    pgv.badge(v_art.categorie, NULL),
    CASE WHEN v_art.active THEN 'Oui' ELSE 'Non' END
  );

  -- Catalog link
  IF v_catalog_link <> '—' THEN
    v_body := v_body || format('<p><strong>Catalog:</strong> %s</p>', v_catalog_link);
  END IF;

  -- Stock par dépôt
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT d.id, d.nom, stock._stock_actuel(p_id, d.id) AS qty
    FROM stock.depot d
    WHERE d.actif
      AND EXISTS (SELECT 1 FROM stock.mouvement m WHERE m.article_id = p_id AND m.depot_id = d.id)
    ORDER BY d.nom
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.esc(r.nom),
      r.qty::text || ' ' || v_art.unite
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>Stock par dépôt</h3>' || pgv.md_table(
      ARRAY['Dépôt', 'Quantité'],
      v_rows
    );
  END IF;

  -- Derniers mouvements
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT m.created_at, d.nom AS depot_nom, m.type, m.quantite, m.prix_unitaire, m.reference
    FROM stock.mouvement m
    JOIN stock.depot d ON d.id = m.depot_id
    WHERE m.article_id = p_id
    ORDER BY m.created_at DESC
    LIMIT 20
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.created_at, 'DD/MM HH24:MI'),
      pgv.esc(r.depot_nom),
      pgv.badge(r.type, CASE r.type
        WHEN 'entree' THEN 'success'
        WHEN 'sortie' THEN 'danger'
        WHEN 'transfert' THEN 'info'
        WHEN 'inventaire' THEN 'warning'
      END),
      r.quantite::text,
      CASE WHEN r.prix_unitaire IS NOT NULL THEN to_char(r.prix_unitaire, 'FM999G990D00') ELSE '—' END,
      coalesce(r.reference, '')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>Mouvements récents</h3>' || pgv.md_table(
      ARRAY['Date', 'Dépôt', 'Type', 'Qté', 'PU', 'Réf.'],
      v_rows, 10
    );
  END IF;

  -- Actions
  v_body := v_body || format('<p><a href="%s" role="button">Modifier</a> ',
    pgv.call_ref('get_article_form', jsonb_build_object('p_id', p_id)));
  v_body := v_body || pgv.action('post_article_delete', 'Désactiver',
    jsonb_build_object('id', p_id), 'Désactiver cet article ?') || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_article(integer) IS 'Fiche article: infos, stock par dépôt, historique mouvements, lien fournisseur CRM, lien catalog';

CREATE OR REPLACE FUNCTION stock.get_article_form(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_art stock.article;
  v_body text;
  v_cat_options text;
  v_unite_options text;
  v_fournisseur_options text;
  v_catalog_search text;
  v_catalog_display text;
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT * INTO v_art FROM stock.article WHERE id = p_id;
    IF NOT FOUND THEN RETURN pgv.empty('Article introuvable', ''); END IF;
  END IF;

  -- Options catégorie
  v_cat_options := '';
  FOR v_cat_options IN SELECT '' LOOP END LOOP; -- reset
  v_cat_options := '<option value="">-- Catégorie --</option>';
  v_cat_options := v_cat_options || format('<option value="bois"%s>Bois</option>', CASE WHEN v_art.categorie = 'bois' THEN ' selected' ELSE '' END);
  v_cat_options := v_cat_options || format('<option value="quincaillerie"%s>Quincaillerie</option>', CASE WHEN v_art.categorie = 'quincaillerie' THEN ' selected' ELSE '' END);
  v_cat_options := v_cat_options || format('<option value="panneau"%s>Panneau</option>', CASE WHEN v_art.categorie = 'panneau' THEN ' selected' ELSE '' END);
  v_cat_options := v_cat_options || format('<option value="isolant"%s>Isolant</option>', CASE WHEN v_art.categorie = 'isolant' THEN ' selected' ELSE '' END);
  v_cat_options := v_cat_options || format('<option value="finition"%s>Finition</option>', CASE WHEN v_art.categorie = 'finition' THEN ' selected' ELSE '' END);
  v_cat_options := v_cat_options || format('<option value="autre"%s>Autre</option>', CASE WHEN v_art.categorie = 'autre' THEN ' selected' ELSE '' END);

  -- Options unité
  v_unite_options := '';
  v_unite_options := format('<option value="u"%s>Unité</option>', CASE WHEN coalesce(v_art.unite, 'u') = 'u' THEN ' selected' ELSE '' END);
  v_unite_options := v_unite_options || format('<option value="m"%s>Mètre</option>', CASE WHEN v_art.unite = 'm' THEN ' selected' ELSE '' END);
  v_unite_options := v_unite_options || format('<option value="m2"%s>m²</option>', CASE WHEN v_art.unite = 'm2' THEN ' selected' ELSE '' END);
  v_unite_options := v_unite_options || format('<option value="m3"%s>m³</option>', CASE WHEN v_art.unite = 'm3' THEN ' selected' ELSE '' END);
  v_unite_options := v_unite_options || format('<option value="kg"%s>kg</option>', CASE WHEN v_art.unite = 'kg' THEN ' selected' ELSE '' END);
  v_unite_options := v_unite_options || format('<option value="l"%s>Litre</option>', CASE WHEN v_art.unite = 'l' THEN ' selected' ELSE '' END);

  -- Options fournisseur (CRM companies)
  v_fournisseur_options := '<option value="">-- Aucun --</option>';
  SELECT v_fournisseur_options || string_agg(
    format('<option value="%s"%s>%s</option>', c.id, CASE WHEN c.id = v_art.fournisseur_id THEN ' selected' ELSE '' END, pgv.esc(c.name)),
    '' ORDER BY c.name
  ) INTO v_fournisseur_options
  FROM crm.client c WHERE c.type = 'company' AND c.active;

  -- Catalog article search (cross-module guard)
  v_catalog_search := '';
  IF EXISTS (SELECT 1 FROM pg_namespace WHERE nspname = 'catalog') THEN
    -- Resolve current display value
    v_catalog_display := NULL;
    IF v_art.catalog_article_id IS NOT NULL THEN
      SELECT ca.designation INTO v_catalog_display
      FROM catalog.article ca WHERE ca.id = v_art.catalog_article_id;
    END IF;
    v_catalog_search := pgv.select_search(
      'catalog_article_id', 'Article catalog',
      'catalog.article_options',
      'Rechercher un article catalog...',
      v_art.catalog_article_id::text,
      v_catalog_display
    );
  END IF;

  v_body := format('<form data-rpc="post_article_save">
    <input type="hidden" name="id" value="%s">
    <label>Référence <input type="text" name="reference" value="%s" required></label>
    <label>Désignation <input type="text" name="designation" value="%s" required></label>
    <label>Catégorie <select name="categorie" required>%s</select></label>
    <label>Unité <select name="unite" required>%s</select></label>
    <label>Prix d''achat <input type="number" name="prix_achat" value="%s" step="0.01" min="0"></label>
    <label>Seuil mini <input type="number" name="seuil_mini" value="%s" step="0.01" min="0"></label>
    <label>Fournisseur <select name="fournisseur_id">%s</select></label>
    %s
    <label>Notes <textarea name="notes">%s</textarea></label>
    <button type="submit">%s</button>
  </form>',
    coalesce(p_id::text, ''),
    coalesce(pgv.esc(v_art.reference), ''),
    coalesce(pgv.esc(v_art.designation), ''),
    v_cat_options,
    v_unite_options,
    coalesce(v_art.prix_achat::text, ''),
    coalesce(v_art.seuil_mini::text, '0'),
    v_fournisseur_options,
    v_catalog_search,
    coalesce(pgv.esc(v_art.notes), ''),
    CASE WHEN p_id IS NOT NULL THEN 'Modifier' ELSE 'Créer' END
  );

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_article_form(integer) IS 'Formulaire création/édition article avec select fournisseur CRM et lien catalog';

CREATE OR REPLACE FUNCTION stock.get_articles()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  r record;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.id, a.reference, a.designation, a.categorie, a.unite,
           a.prix_achat, a.pmp, a.seuil_mini, a.active, a.fournisseur_id,
           stock._stock_actuel(a.id) AS qty,
           c.name AS fournisseur
    FROM stock.article a
    LEFT JOIN crm.client c ON c.id = a.fournisseur_id
    ORDER BY a.designation
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_article', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
      pgv.esc(r.designation),
      pgv.badge(r.categorie, CASE r.categorie
        WHEN 'bois' THEN 'success'
        WHEN 'quincaillerie' THEN 'info'
        WHEN 'panneau' THEN 'warning'
        ELSE NULL
      END),
      r.qty::text || ' ' || r.unite,
      CASE WHEN r.pmp > 0 THEN to_char(r.pmp, 'FM999G990D00') ELSE '—' END,
      CASE WHEN r.seuil_mini > 0 AND r.qty < r.seuil_mini
        THEN pgv.badge('ALERTE', 'danger')
        ELSE '—'
      END,
      CASE WHEN r.fournisseur IS NOT NULL
        THEN format('<a href="/crm/client?p_id=%s">%s</a>', r.fournisseur_id, pgv.esc(r.fournisseur))
        ELSE '—'
      END,
      CASE WHEN r.active THEN 'Oui' ELSE 'Non' END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty('Aucun article', 'Créez votre premier article pour commencer.');
  ELSE
    v_body := pgv.md_table(
      ARRAY['Réf.', 'Désignation', 'Catégorie', 'Stock', 'PMP', 'Alerte', 'Fournisseur', 'Actif'],
      v_rows,
      20
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">Nouvel article</a></p>',
    pgv.call_ref('get_article_form'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_articles() IS 'Liste des articles avec stock actuel, PMP, alertes, lien fournisseur CRM';

CREATE OR REPLACE FUNCTION stock.get_depot(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_dep stock.depot;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  SELECT * INTO v_dep FROM stock.depot WHERE id = p_id;
  IF NOT FOUND THEN RETURN pgv.empty('Dépôt introuvable', ''); END IF;

  v_body := format('<p><strong>Type:</strong> %s | <strong>Adresse:</strong> %s | <strong>Actif:</strong> %s</p>',
    pgv.badge(v_dep.type, NULL),
    coalesce(pgv.esc(v_dep.adresse), '—'),
    CASE WHEN v_dep.actif THEN 'Oui' ELSE 'Non' END
  );

  -- Contenu du dépôt
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.id, a.reference, a.designation, a.unite,
           stock._stock_actuel(a.id, p_id) AS qty
    FROM stock.article a
    WHERE a.active
      AND EXISTS (SELECT 1 FROM stock.mouvement m WHERE m.article_id = a.id AND m.depot_id = p_id)
    ORDER BY a.designation
  LOOP
    IF r.qty <> 0 THEN
      v_rows := v_rows || ARRAY[
        format('<a href="%s">%s</a>', pgv.call_ref('get_article', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
        pgv.esc(r.designation),
        r.qty::text || ' ' || r.unite
      ];
    END IF;
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>Contenu</h3>' || pgv.md_table(
      ARRAY['Réf.', 'Désignation', 'Quantité'],
      v_rows
    );
  ELSE
    v_body := v_body || pgv.empty('Dépôt vide', '');
  END IF;

  -- Derniers mouvements
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT m.created_at, a.designation, m.type, m.quantite, m.reference
    FROM stock.mouvement m
    JOIN stock.article a ON a.id = m.article_id
    WHERE m.depot_id = p_id
    ORDER BY m.created_at DESC
    LIMIT 20
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.created_at, 'DD/MM HH24:MI'),
      pgv.esc(r.designation),
      pgv.badge(r.type, CASE r.type
        WHEN 'entree' THEN 'success'
        WHEN 'sortie' THEN 'danger'
        WHEN 'transfert' THEN 'info'
        WHEN 'inventaire' THEN 'warning'
      END),
      r.quantite::text,
      coalesce(r.reference, '')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>Mouvements récents</h3>' || pgv.md_table(
      ARRAY['Date', 'Article', 'Type', 'Qté', 'Réf.'],
      v_rows, 10
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">Modifier</a></p>',
    pgv.call_ref('get_depot_form', jsonb_build_object('p_id', p_id)));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_depot(integer) IS 'Fiche dépôt: contenu + mouvements récents';

CREATE OR REPLACE FUNCTION stock.get_depot_form(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_dep stock.depot;
  v_type_options text;
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT * INTO v_dep FROM stock.depot WHERE id = p_id;
    IF NOT FOUND THEN RETURN pgv.empty('Dépôt introuvable', ''); END IF;
  END IF;

  v_type_options := '<option value="">-- Type --</option>';
  v_type_options := v_type_options || format('<option value="atelier"%s>Atelier</option>', CASE WHEN v_dep.type = 'atelier' THEN ' selected' ELSE '' END);
  v_type_options := v_type_options || format('<option value="chantier"%s>Chantier</option>', CASE WHEN v_dep.type = 'chantier' THEN ' selected' ELSE '' END);
  v_type_options := v_type_options || format('<option value="vehicule"%s>Véhicule</option>', CASE WHEN v_dep.type = 'vehicule' THEN ' selected' ELSE '' END);
  v_type_options := v_type_options || format('<option value="entrepot"%s>Entrepôt</option>', CASE WHEN v_dep.type = 'entrepot' THEN ' selected' ELSE '' END);

  RETURN format('<form data-rpc="post_depot_save">
    <input type="hidden" name="id" value="%s">
    <label>Nom <input type="text" name="nom" value="%s" required></label>
    <label>Type <select name="type" required>%s</select></label>
    <label>Adresse <input type="text" name="adresse" value="%s"></label>
    <button type="submit">%s</button>
  </form>',
    coalesce(p_id::text, ''),
    coalesce(pgv.esc(v_dep.nom), ''),
    v_type_options,
    coalesce(pgv.esc(v_dep.adresse), ''),
    CASE WHEN p_id IS NOT NULL THEN 'Modifier' ELSE 'Créer' END
  );
END;
$function$;
COMMENT ON FUNCTION stock.get_depot_form(integer) IS 'Formulaire création/édition dépôt';

CREATE OR REPLACE FUNCTION stock.get_depots()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  r record;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT d.id, d.nom, d.type, d.adresse, d.actif,
           (SELECT count(DISTINCT m.article_id) FROM stock.mouvement m WHERE m.depot_id = d.id)::int AS nb_articles
    FROM stock.depot d
    ORDER BY d.nom
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_depot', jsonb_build_object('p_id', r.id)), pgv.esc(r.nom)),
      pgv.badge(r.type, CASE r.type
        WHEN 'atelier' THEN 'success'
        WHEN 'chantier' THEN 'warning'
        WHEN 'vehicule' THEN 'info'
        WHEN 'entrepot' THEN NULL
      END),
      coalesce(r.adresse, '—'),
      r.nb_articles::text,
      CASE WHEN r.actif THEN 'Oui' ELSE 'Non' END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty('Aucun dépôt', 'Créez votre premier dépôt pour commencer.');
  ELSE
    v_body := pgv.md_table(
      ARRAY['Nom', 'Type', 'Adresse', 'Articles', 'Actif'],
      v_rows
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">Nouveau dépôt</a></p>',
    pgv.call_ref('get_depot_form'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_depots() IS 'Liste des dépôts avec nombre d''articles stockés';

CREATE OR REPLACE FUNCTION stock.get_index()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_nb_articles int;
  v_nb_alertes int;
  v_nb_mouvements_mois int;
  v_valeur_totale numeric;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  SELECT count(*)::int INTO v_nb_articles FROM stock.article WHERE active;

  -- Articles sous seuil
  SELECT count(*)::int INTO v_nb_alertes
  FROM stock.article a
  WHERE a.active AND a.seuil_mini > 0
    AND stock._stock_actuel(a.id) < a.seuil_mini;

  SELECT count(*)::int INTO v_nb_mouvements_mois
  FROM stock.mouvement
  WHERE created_at >= date_trunc('month', now());

  -- Valeur totale du stock (quantité * PMP par article)
  SELECT coalesce(sum(stock._stock_actuel(a.id) * a.pmp), 0)
  INTO v_valeur_totale
  FROM stock.article a
  WHERE a.active AND a.pmp > 0;

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Articles', v_nb_articles::text),
    pgv.stat('Valeur stock', to_char(v_valeur_totale, 'FM999G999G990D00') || ' EUR'),
    pgv.stat('Alertes', v_nb_alertes::text, CASE WHEN v_nb_alertes > 0 THEN 'danger' ELSE NULL END),
    pgv.stat('Mouvements ce mois', v_nb_mouvements_mois::text)
  ]);

  -- Derniers mouvements
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT m.created_at, a.designation, d.nom AS depot_nom, m.type, m.quantite, m.reference
    FROM stock.mouvement m
    JOIN stock.article a ON a.id = m.article_id
    JOIN stock.depot d ON d.id = m.depot_id
    ORDER BY m.created_at DESC
    LIMIT 10
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.created_at, 'DD/MM HH24:MI'),
      pgv.esc(r.designation),
      pgv.esc(r.depot_nom),
      pgv.badge(r.type, CASE r.type
        WHEN 'entree' THEN 'success'
        WHEN 'sortie' THEN 'danger'
        WHEN 'transfert' THEN 'info'
        WHEN 'inventaire' THEN 'warning'
      END),
      r.quantite::text,
      coalesce(r.reference, '')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucun mouvement', 'Enregistrez votre premier mouvement de stock.');
  ELSE
    v_body := v_body || '<h3>Derniers mouvements</h3>' || pgv.md_table(
      ARRAY['Date', 'Article', 'Dépôt', 'Type', 'Qté', 'Réf.'],
      v_rows
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">Nouveau mouvement</a></p>',
    pgv.call_ref('get_mouvement_form'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_index() IS 'Dashboard stock: stats (articles, valeur totale, alertes, mouvements) + derniers mouvements';

CREATE OR REPLACE FUNCTION stock.get_inventaire(p_depot_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_depot_nom text;
  v_rows text[];
  r record;
  v_qty numeric;
BEGIN
  -- Si pas de dépôt sélectionné, afficher le choix
  IF p_depot_id IS NULL THEN
    v_rows := ARRAY[]::text[];
    FOR r IN
      SELECT d.id, d.nom, d.type FROM stock.depot d WHERE d.actif ORDER BY d.nom
    LOOP
      v_rows := v_rows || ARRAY[
        format('<a href="%s">%s</a>',
          pgv.call_ref('get_inventaire', jsonb_build_object('p_depot_id', r.id)),
          pgv.esc(r.nom)),
        pgv.badge(r.type, CASE r.type
          WHEN 'entrepot' THEN 'info'
          WHEN 'atelier' THEN 'success'
          WHEN 'chantier' THEN 'warning'
          WHEN 'vehicule' THEN 'primary'
        END)
      ];
    END LOOP;

    IF array_length(v_rows, 1) IS NULL THEN
      RETURN pgv.empty('Aucun dépôt', 'Créez un dépôt avant de faire un inventaire.');
    END IF;

    RETURN '<p>Sélectionnez le dépôt à inventorier :</p>' || pgv.md_table(
      ARRAY['Dépôt', 'Type'],
      v_rows
    );
  END IF;

  SELECT nom INTO v_depot_nom FROM stock.depot WHERE id = p_depot_id AND actif;
  IF v_depot_nom IS NULL THEN
    RETURN pgv.empty('Dépôt introuvable', 'Ce dépôt n''existe pas ou est inactif.');
  END IF;

  v_body := format('<h3>Inventaire : %s</h3>', pgv.esc(v_depot_nom));
  v_body := v_body || format('<form data-rpc="post_inventaire_valider"><input type="hidden" name="p_depot_id" value="%s">', p_depot_id);

  -- Liste des articles avec stock théorique
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.id, a.reference, a.designation, a.unite
    FROM stock.article a
    WHERE a.active
    ORDER BY a.designation
  LOOP
    v_qty := stock._stock_actuel(r.id, p_depot_id);
    v_rows := v_rows || ARRAY[
      pgv.esc(r.reference),
      pgv.esc(r.designation),
      r.unite,
      v_qty::text,
      format('<input type="number" name="qty_%s" value="%s" step="0.01" class="pgv-input-sm">', r.id, v_qty)
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucun article', 'Aucun article actif dans le catalogue.');
    v_body := v_body || '</form>';
    RETURN v_body;
  END IF;

  v_body := v_body || pgv.md_table(
    ARRAY['Réf.', 'Désignation', 'Unité', 'Théorique', 'Réel'],
    v_rows
  );

  v_body := v_body || '<p><button type="submit" class="pgv-btn-primary">Valider l''inventaire</button></p></form>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_inventaire(integer) IS 'Formulaire d inventaire physique pour un dépôt — saisie quantités réelles';

CREATE OR REPLACE FUNCTION stock.get_mouvement_form(p_type text DEFAULT 'entree'::text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_depot_options text;
  v_type_options text;
  v_body text;
  v_article_search text;
BEGIN
  -- Article via select_search
  v_article_search := pgv.select_search(
    'article_id', 'Article',
    'article_options',
    'Rechercher un article...'
  );

  -- Dépôts actifs
  v_depot_options := '<option value="">-- Dépôt --</option>';
  SELECT v_depot_options || string_agg(
    format('<option value="%s">%s</option>', d.id, pgv.esc(d.nom)),
    '' ORDER BY d.nom
  ) INTO v_depot_options
  FROM stock.depot d WHERE d.actif;

  -- Type
  v_type_options := format('<option value="entree"%s>Entrée</option>', CASE WHEN p_type = 'entree' THEN ' selected' ELSE '' END);
  v_type_options := v_type_options || format('<option value="sortie"%s>Sortie</option>', CASE WHEN p_type = 'sortie' THEN ' selected' ELSE '' END);
  v_type_options := v_type_options || format('<option value="transfert"%s>Transfert</option>', CASE WHEN p_type = 'transfert' THEN ' selected' ELSE '' END);
  v_type_options := v_type_options || format('<option value="inventaire"%s>Inventaire</option>', CASE WHEN p_type = 'inventaire' THEN ' selected' ELSE '' END);

  v_body := format('<form data-rpc="post_mouvement_save">
    <label>Type <select name="type" required>%s</select></label>
    %s
    <label>Dépôt <select name="depot_id" required>%s</select></label>
    <label>Quantité <input type="number" name="quantite" step="0.01" min="0.01" required></label>
    <label>Prix unitaire <input type="number" name="prix_unitaire" step="0.01" min="0"></label>
    <label>Dépôt destination (transfert) <select name="depot_destination_id">%s</select></label>
    <label>Référence doc <input type="text" name="reference" placeholder="N° BL, commande..."></label>
    <label>Notes <textarea name="notes"></textarea></label>
    <button type="submit">Enregistrer</button>
  </form>',
    v_type_options,
    v_article_search,
    v_depot_options,
    v_depot_options  -- same options for destination
  );

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_mouvement_form(text) IS 'Formulaire de saisie mouvement avec select_search article';

CREATE OR REPLACE FUNCTION stock.get_mouvements()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  r record;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT m.id, m.created_at, a.reference, a.designation, d.nom AS depot_nom,
           m.type, m.quantite, m.prix_unitaire, m.reference AS ref_doc,
           dd.nom AS dest_nom
    FROM stock.mouvement m
    JOIN stock.article a ON a.id = m.article_id
    JOIN stock.depot d ON d.id = m.depot_id
    LEFT JOIN stock.depot dd ON dd.id = m.depot_destination_id
    ORDER BY m.created_at DESC
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.created_at, 'DD/MM/YY HH24:MI'),
      format('<a href="%s">%s</a>', pgv.call_ref('get_article', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
      pgv.esc(r.designation),
      pgv.esc(r.depot_nom) || CASE WHEN r.dest_nom IS NOT NULL THEN ' -> ' || pgv.esc(r.dest_nom) ELSE '' END,
      pgv.badge(r.type, CASE r.type
        WHEN 'entree' THEN 'success'
        WHEN 'sortie' THEN 'danger'
        WHEN 'transfert' THEN 'info'
        WHEN 'inventaire' THEN 'warning'
      END),
      r.quantite::text,
      coalesce(r.ref_doc, '')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty('Aucun mouvement', 'Enregistrez votre premier mouvement.');
  ELSE
    v_body := pgv.md_table(
      ARRAY['Date', 'Réf.', 'Article', 'Dépôt', 'Type', 'Qté', 'Réf. doc'],
      v_rows, 20
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">Nouveau mouvement</a></p>',
    pgv.call_ref('get_mouvement_form'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_mouvements() IS 'Historique des mouvements de stock';

CREATE OR REPLACE FUNCTION stock.get_valorisation()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_valeur_totale numeric;
  v_nb_articles int;
  v_nb_alertes int;
  v_rows text[];
  r record;
BEGIN
  -- Stats globales
  SELECT count(*)::int INTO v_nb_articles FROM stock.article WHERE active;

  SELECT coalesce(sum(stock._stock_actuel(a.id) * a.pmp), 0)
  INTO v_valeur_totale
  FROM stock.article a WHERE a.active AND a.pmp > 0;

  SELECT count(*)::int INTO v_nb_alertes
  FROM stock.article a
  WHERE a.active AND a.seuil_mini > 0
    AND stock._stock_actuel(a.id) < a.seuil_mini;

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Valeur totale', to_char(v_valeur_totale, 'FM999G999G990D00') || ' EUR'),
    pgv.stat('Articles en stock', v_nb_articles::text),
    pgv.stat('En alerte', v_nb_alertes::text, CASE WHEN v_nb_alertes > 0 THEN 'danger' ELSE NULL END)
  ]);

  -- Valorisation par dépôt
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT d.nom AS depot_nom, d.type AS depot_type,
           count(DISTINCT m.article_id)::int AS nb_articles,
           coalesce(sum(m.quantite * a.pmp), 0) AS valeur
    FROM stock.depot d
    LEFT JOIN stock.mouvement m ON m.depot_id = d.id
    LEFT JOIN stock.article a ON a.id = m.article_id AND a.active
    WHERE d.actif
    GROUP BY d.id, d.nom, d.type
    ORDER BY valeur DESC
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.esc(r.depot_nom),
      pgv.badge(r.depot_type, CASE r.depot_type
        WHEN 'entrepot' THEN 'info'
        WHEN 'atelier' THEN 'success'
        WHEN 'chantier' THEN 'warning'
        WHEN 'vehicule' THEN 'primary'
      END),
      r.nb_articles::text,
      to_char(r.valeur, 'FM999G999G990D00') || ' EUR'
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>Par dépôt</h3>' || pgv.md_table(
      ARRAY['Dépôt', 'Type', 'Articles', 'Valeur'],
      v_rows
    );
  END IF;

  -- Valorisation par catégorie
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.categorie,
           count(*)::int AS nb_articles,
           coalesce(sum(stock._stock_actuel(a.id) * a.pmp), 0) AS valeur
    FROM stock.article a
    WHERE a.active AND a.pmp > 0
    GROUP BY a.categorie
    ORDER BY valeur DESC
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.badge(r.categorie, CASE r.categorie
        WHEN 'bois' THEN 'success'
        WHEN 'quincaillerie' THEN 'info'
        WHEN 'panneau' THEN 'warning'
        WHEN 'isolant' THEN 'primary'
        WHEN 'finition' THEN 'default'
        ELSE NULL
      END),
      r.nb_articles::text,
      to_char(r.valeur, 'FM999G999G990D00') || ' EUR'
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>Par catégorie</h3>' || pgv.md_table(
      ARRAY['Catégorie', 'Articles', 'Valeur'],
      v_rows
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_valorisation() IS 'Valorisation du stock par dépôt et catégorie, avec totaux';

CREATE OR REPLACE FUNCTION stock.nav_items()
 RETURNS jsonb
 LANGUAGE sql
 STABLE
AS $function$
  SELECT jsonb_build_array(
    jsonb_build_object('label', 'Articles',      'href', '/articles'),
    jsonb_build_object('label', 'Dépôts',        'href', '/depots'),
    jsonb_build_object('label', 'Mouvements',    'href', '/mouvements'),
    jsonb_build_object('label', 'Alertes',       'href', '/alertes'),
    jsonb_build_object('label', 'Valorisation',  'href', '/valorisation'),
    jsonb_build_object('label', 'Inventaire',    'href', '/inventaire')
  );
$function$;
COMMENT ON FUNCTION stock.nav_items() IS 'Menu de navigation du module stock';

CREATE OR REPLACE FUNCTION stock.post_article_delete(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  UPDATE stock.article SET active = false WHERE id = (p_data->>'id')::int;

  RETURN '<template data-toast="success">Article désactivé</template>'
    || format('<template data-redirect="%s"></template>', pgv.call_ref('get_articles'));
END;
$function$;
COMMENT ON FUNCTION stock.post_article_delete(jsonb) IS 'Désactiver un article (soft delete)';

CREATE OR REPLACE FUNCTION stock.post_article_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
BEGIN
  v_id := (p_data->>'id')::int;

  IF v_id IS NOT NULL AND v_id > 0 THEN
    UPDATE stock.article SET
      reference = p_data->>'reference',
      designation = p_data->>'designation',
      categorie = p_data->>'categorie',
      unite = p_data->>'unite',
      prix_achat = nullif(p_data->>'prix_achat', '')::numeric,
      seuil_mini = coalesce(nullif(p_data->>'seuil_mini', '')::numeric, 0),
      fournisseur_id = nullif(p_data->>'fournisseur_id', '')::int,
      catalog_article_id = nullif(p_data->>'catalog_article_id', '')::int,
      notes = coalesce(p_data->>'notes', '')
    WHERE id = v_id;

    RETURN '<template data-toast="success">Article modifié</template>'
      || format('<template data-redirect="%s"></template>', pgv.call_ref('get_article', jsonb_build_object('p_id', v_id)));
  ELSE
    INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, seuil_mini, fournisseur_id, catalog_article_id, notes)
    VALUES (
      p_data->>'reference',
      p_data->>'designation',
      p_data->>'categorie',
      p_data->>'unite',
      nullif(p_data->>'prix_achat', '')::numeric,
      coalesce(nullif(p_data->>'seuil_mini', '')::numeric, 0),
      nullif(p_data->>'fournisseur_id', '')::int,
      nullif(p_data->>'catalog_article_id', '')::int,
      coalesce(p_data->>'notes', '')
    ) RETURNING id INTO v_id;

    RETURN '<template data-toast="success">Article créé</template>'
      || format('<template data-redirect="%s"></template>', pgv.call_ref('get_article', jsonb_build_object('p_id', v_id)));
  END IF;
END;
$function$;
COMMENT ON FUNCTION stock.post_article_save(jsonb) IS 'Créer ou modifier un article (avec lien catalog optionnel)';

CREATE OR REPLACE FUNCTION stock.post_depot_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
BEGIN
  v_id := (p_data->>'id')::int;

  IF v_id IS NOT NULL AND v_id > 0 THEN
    UPDATE stock.depot SET
      nom = p_data->>'nom',
      type = p_data->>'type',
      adresse = nullif(p_data->>'adresse', '')
    WHERE id = v_id;

    RETURN '<template data-toast="success">Dépôt modifié</template>'
      || format('<template data-redirect="%s"></template>', pgv.call_ref('get_depot', jsonb_build_object('p_id', v_id)));
  ELSE
    INSERT INTO stock.depot (nom, type, adresse)
    VALUES (p_data->>'nom', p_data->>'type', nullif(p_data->>'adresse', ''))
    RETURNING id INTO v_id;

    RETURN '<template data-toast="success">Dépôt créé</template>'
      || format('<template data-redirect="%s"></template>', pgv.call_ref('get_depot', jsonb_build_object('p_id', v_id)));
  END IF;
END;
$function$;
COMMENT ON FUNCTION stock.post_depot_save(jsonb) IS 'Créer ou modifier un dépôt';

CREATE OR REPLACE FUNCTION stock.post_inventaire_valider(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_depot_id int := (p_data->>'p_depot_id')::int;
  v_key text;
  v_val text;
  v_article_id int;
  v_qty_reelle numeric;
  v_qty_theorique numeric;
  v_ecart numeric;
  v_nb_ajustements int := 0;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM stock.depot WHERE id = v_depot_id AND actif) THEN
    RETURN '<template data-toast="error">Dépôt introuvable</template>';
  END IF;

  -- Parcourir les champs qty_* du formulaire
  FOR v_key, v_val IN SELECT key, value FROM jsonb_each_text(p_data) WHERE key LIKE 'qty_%'
  LOOP
    v_article_id := replace(v_key, 'qty_', '')::int;
    v_qty_reelle := v_val::numeric;
    v_qty_theorique := stock._stock_actuel(v_article_id, v_depot_id);
    v_ecart := v_qty_reelle - v_qty_theorique;

    IF v_ecart = 0 THEN
      CONTINUE;
    END IF;

    -- Mouvement inventaire: positif = entrée, négatif = sortie (quantite signée)
    INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, reference)
    VALUES (v_article_id, v_depot_id, 'inventaire', v_ecart,
            'INV-' || to_char(now(), 'YYYYMMDD'));

    v_nb_ajustements := v_nb_ajustements + 1;
  END LOOP;

  IF v_nb_ajustements = 0 THEN
    RETURN format('<template data-toast="success">Stock conforme — aucun ajustement</template><template data-redirect="%s"></template>',
      pgv.call_ref('get_inventaire', jsonb_build_object('p_depot_id', v_depot_id)));
  END IF;

  RETURN format('<template data-toast="success">Inventaire validé — %s ajustement(s)</template><template data-redirect="%s"></template>',
    v_nb_ajustements,
    pgv.call_ref('get_depot', jsonb_build_object('p_id', v_depot_id)));
END;
$function$;
COMMENT ON FUNCTION stock.post_inventaire_valider(jsonb) IS 'Valide un inventaire physique — génère mouvements d écart pour chaque article';

CREATE OR REPLACE FUNCTION stock.post_mouvement_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_type text;
  v_article_id int;
  v_depot_id int;
  v_dest_id int;
  v_qty numeric;
  v_pu numeric;
  v_art stock.article;
BEGIN
  v_type := p_data->>'type';
  v_article_id := (p_data->>'article_id')::int;
  v_depot_id := (p_data->>'depot_id')::int;
  v_dest_id := nullif(p_data->>'depot_destination_id', '')::int;
  v_qty := (p_data->>'quantite')::numeric;
  v_pu := nullif(p_data->>'prix_unitaire', '')::numeric;

  SELECT * INTO v_art FROM stock.article WHERE id = v_article_id;
  IF NOT FOUND THEN
    RETURN '<template data-toast="error">Article introuvable</template>';
  END IF;

  -- Validate transfert
  IF v_type = 'transfert' AND v_dest_id IS NULL THEN
    RETURN '<template data-toast="error">Dépôt destination requis pour un transfert</template>';
  END IF;
  IF v_type = 'transfert' AND v_depot_id = v_dest_id THEN
    RETURN '<template data-toast="error">Dépôt source et destination identiques</template>';
  END IF;

  -- Check stock suffisant pour sortie
  IF v_type = 'sortie' THEN
    IF stock._stock_actuel(v_article_id, v_depot_id) < v_qty THEN
      RETURN '<template data-toast="error">Stock insuffisant dans ce dépôt</template>';
    END IF;
  END IF;

  IF v_type = 'entree' THEN
    -- Entrée: quantité positive, PU fourni ou prix_achat
    INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, notes)
    VALUES (v_article_id, v_depot_id, 'entree', v_qty, coalesce(v_pu, v_art.prix_achat), nullif(p_data->>'reference', ''), coalesce(p_data->>'notes', ''));

    -- Recalc PMP + update prix_achat
    PERFORM stock._recalc_pmp(v_article_id);
    IF v_pu IS NOT NULL THEN
      UPDATE stock.article SET prix_achat = v_pu WHERE id = v_article_id;
    END IF;

  ELSIF v_type = 'sortie' THEN
    -- Sortie: quantité négative, PU = PMP figé
    INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, notes)
    VALUES (v_article_id, v_depot_id, 'sortie', -v_qty, v_art.pmp, nullif(p_data->>'reference', ''), coalesce(p_data->>'notes', ''));

  ELSIF v_type = 'transfert' THEN
    -- Transfert: sortie du dépôt source + entrée au dépôt destination
    IF stock._stock_actuel(v_article_id, v_depot_id) < v_qty THEN
      RETURN '<template data-toast="error">Stock insuffisant pour le transfert</template>';
    END IF;

    INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, depot_destination_id, notes)
    VALUES (v_article_id, v_depot_id, 'transfert', -v_qty, v_art.pmp, nullif(p_data->>'reference', ''), v_dest_id, coalesce(p_data->>'notes', ''));

    INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, depot_destination_id, notes)
    VALUES (v_article_id, v_dest_id, 'transfert', v_qty, v_art.pmp, nullif(p_data->>'reference', ''), v_depot_id, coalesce(p_data->>'notes', ''));

  ELSIF v_type = 'inventaire' THEN
    -- Inventaire: ajustement pour corriger l'écart
    DECLARE
      v_stock_actuel numeric;
      v_ecart numeric;
    BEGIN
      v_stock_actuel := stock._stock_actuel(v_article_id, v_depot_id);
      v_ecart := v_qty - v_stock_actuel;

      IF v_ecart = 0 THEN
        RETURN '<template data-toast="success">Stock déjà correct, aucun ajustement</template>';
      END IF;

      INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, notes)
      VALUES (v_article_id, v_depot_id, 'inventaire', v_ecart, v_art.pmp,
              'INV-' || to_char(now(), 'YYYYMMDD'),
              format('Inventaire: %s -> %s (écart: %s)', v_stock_actuel, v_qty, v_ecart));
    END;
  END IF;

  RETURN '<template data-toast="success">Mouvement enregistré</template>'
    || format('<template data-redirect="%s"></template>', pgv.call_ref('get_mouvements'));
END;
$function$;
COMMENT ON FUNCTION stock.post_mouvement_save(jsonb) IS 'Enregistrer un mouvement de stock (entrée/sortie/transfert/inventaire) avec recalcul PMP';

GRANT USAGE ON SCHEMA stock TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA stock TO web_anon;

