CREATE OR REPLACE FUNCTION stock_ut.test_mouvement_transfert()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_art_id int;
  v_dep_a int;
  v_dep_b int;
  v_qty_a numeric;
  v_qty_b numeric;
  v_result text;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  INSERT INTO stock.depot (nom, type, tenant_id) VALUES ('Depot A', 'atelier', 'test') RETURNING id INTO v_dep_a;
  INSERT INTO stock.depot (nom, type, tenant_id) VALUES ('Depot B', 'vehicule', 'test') RETURNING id INTO v_dep_b;
  INSERT INTO stock.article (reference, designation, categorie, pmp, tenant_id) VALUES ('TEST-T01', 'Transfert test', 'bois', 50.0000, 'test') RETURNING id INTO v_art_id;

  -- Stock initial
  INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, tenant_id)
  VALUES (v_art_id, v_dep_a, 'entree', 20, 50.00, 'test');

  -- Transfert A -> B
  v_result := stock.post_mouvement_save(jsonb_build_object(
    'type', 'transfert', 'article_id', v_art_id, 'depot_id', v_dep_a,
    'depot_destination_id', v_dep_b, 'quantite', '8'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'transfert success');

  SELECT coalesce(sum(quantite), 0) INTO v_qty_a FROM stock.mouvement WHERE article_id = v_art_id AND depot_id = v_dep_a;
  SELECT coalesce(sum(quantite), 0) INTO v_qty_b FROM stock.mouvement WHERE article_id = v_art_id AND depot_id = v_dep_b;
  RETURN NEXT is(v_qty_a, 12::numeric, 'depot A stock = 12');
  RETURN NEXT is(v_qty_b, 8::numeric, 'depot B stock = 8');

  -- Transfert same depot blocked
  v_result := stock.post_mouvement_save(jsonb_build_object(
    'type', 'transfert', 'article_id', v_art_id, 'depot_id', v_dep_a,
    'depot_destination_id', v_dep_a, 'quantite', '5'
  ));
  RETURN NEXT ok(v_result LIKE '%identiques%', 'same depot blocked');

  -- Cleanup
  DELETE FROM stock.mouvement WHERE tenant_id = 'test';
  DELETE FROM stock.article WHERE tenant_id = 'test';
  DELETE FROM stock.depot WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION stock_ut.test_mouvement_transfert() IS 'Test mouvement transfert: 2 mouvements, vérif stock A et B';

CREATE OR REPLACE FUNCTION stock_ut.test_post_article_delete()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_result text;
  v_art stock.article;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  INSERT INTO stock.article (reference, designation, categorie, tenant_id)
  VALUES ('TEST-DEL-01', 'À désactiver', 'bois', 'test')
  RETURNING id INTO v_id;

  v_result := stock.post_article_delete(jsonb_build_object('id', v_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'delete returns success');
  RETURN NEXT ok(v_result LIKE '%data-redirect%', 'delete returns redirect');

  SELECT * INTO v_art FROM stock.article WHERE id = v_id;
  RETURN NEXT is(v_art.active, false, 'article soft-deleted');

  -- Cleanup
  DELETE FROM stock.article WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION stock_ut.test_post_article_delete() IS 'Test post_article_delete: soft delete';

CREATE OR REPLACE FUNCTION stock_ut.test_post_article_save()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
  v_art stock.article;
  v_id int;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Create
  v_result := stock.post_article_save(jsonb_build_object(
    'reference', 'TEST-SAVE-01', 'designation', 'Article test save',
    'categorie', 'bois', 'unite', 'm3', 'prix_achat', '100', 'seuil_mini', '5'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'create returns success');
  RETURN NEXT ok(v_result LIKE '%data-redirect%', 'create returns redirect');

  SELECT id INTO v_id FROM stock.article WHERE reference = 'TEST-SAVE-01' AND tenant_id = 'test';
  SELECT * INTO v_art FROM stock.article WHERE id = v_id;
  RETURN NEXT ok(FOUND, 'article created in DB');
  RETURN NEXT is(v_art.designation, 'Article test save', 'designation saved');
  RETURN NEXT is(v_art.categorie, 'bois', 'categorie saved');
  RETURN NEXT is(v_art.unite, 'm3', 'unite saved');
  RETURN NEXT is(v_art.prix_achat, 100::numeric(12,2), 'prix_achat saved');
  RETURN NEXT is(v_art.seuil_mini, 5::numeric(10,2), 'seuil_mini saved');

  -- Update
  v_result := stock.post_article_save(jsonb_build_object(
    'id', v_id, 'reference', 'TEST-SAVE-01', 'designation', 'Article modifié',
    'categorie', 'quincaillerie', 'unite', 'u', 'prix_achat', '200', 'seuil_mini', '10'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'update returns success');

  SELECT * INTO v_art FROM stock.article WHERE id = v_id;
  RETURN NEXT is(v_art.designation, 'Article modifié', 'designation updated');
  RETURN NEXT is(v_art.categorie, 'quincaillerie', 'categorie updated');
  RETURN NEXT is(v_art.prix_achat, 200::numeric(12,2), 'prix_achat updated');

  -- Cleanup
  DELETE FROM stock.article WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION stock_ut.test_post_article_save() IS 'Test post_article_save: create + update';

CREATE OR REPLACE FUNCTION stock_ut.test_post_depot_save()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
  v_dep stock.depot;
  v_id int;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Create
  v_result := stock.post_depot_save(jsonb_build_object(
    'nom', 'Dépôt test', 'type', 'atelier', 'adresse', '1 rue Test'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'create returns success');
  RETURN NEXT ok(v_result LIKE '%data-redirect%', 'create returns redirect');

  SELECT id INTO v_id FROM stock.depot WHERE nom = 'Dépôt test' AND tenant_id = 'test';
  SELECT * INTO v_dep FROM stock.depot WHERE id = v_id;
  RETURN NEXT ok(FOUND, 'depot created in DB');
  RETURN NEXT is(v_dep.type, 'atelier', 'type saved');
  RETURN NEXT is(v_dep.adresse, '1 rue Test', 'adresse saved');

  -- Update
  v_result := stock.post_depot_save(jsonb_build_object(
    'id', v_id, 'nom', 'Dépôt modifié', 'type', 'chantier', 'adresse', '2 rue Modif'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'update returns success');

  SELECT * INTO v_dep FROM stock.depot WHERE id = v_id;
  RETURN NEXT is(v_dep.nom, 'Dépôt modifié', 'nom updated');
  RETURN NEXT is(v_dep.type, 'chantier', 'type updated');

  -- Cleanup
  DELETE FROM stock.depot WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION stock_ut.test_post_depot_save() IS 'Test post_depot_save: create + update';

CREATE OR REPLACE FUNCTION stock_ut.test_post_inventaire_valider()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_fournisseur_id int;
  v_depot_id int;
  v_art1_id int;
  v_art2_id int;
  v_result text;
  v_stock numeric;
BEGIN
  -- Setup
  INSERT INTO crm.client (type, name) VALUES ('company', 'UT Inv Fournisseur')
  RETURNING id INTO v_fournisseur_id;

  INSERT INTO stock.depot (nom, type) VALUES ('UT Inv Depot', 'entrepot')
  RETURNING id INTO v_depot_id;

  INSERT INTO stock.article (reference, designation, categorie, unite, fournisseur_id)
  VALUES ('UT-INV-001', 'Planche chêne', 'bois', 'm', v_fournisseur_id)
  RETURNING id INTO v_art1_id;

  INSERT INTO stock.article (reference, designation, categorie, unite, fournisseur_id)
  VALUES ('UT-INV-002', 'Colle PU', 'finition', 'l', v_fournisseur_id)
  RETURNING id INTO v_art2_id;

  -- Seed stock: art1=10, art2=5
  INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference)
  VALUES (v_art1_id, v_depot_id, 'entree', 10, 8.00, 'SEED'),
         (v_art2_id, v_depot_id, 'entree', 5, 12.00, 'SEED');

  -- Test 1: inventaire avec écarts (art1: 10->7, art2: 5->5 no change)
  v_result := stock.post_inventaire_valider(jsonb_build_object(
    'p_depot_id', v_depot_id,
    'qty_' || v_art1_id, '7',
    'qty_' || v_art2_id, '5'
  ));
  RETURN NEXT ok(v_result LIKE '%Inventaire validé%', 'inventaire success toast');
  RETURN NEXT ok(v_result LIKE '%1 ajustement%', '1 adjustment (art2 unchanged)');

  SELECT sum(quantite) INTO v_stock FROM stock.mouvement WHERE article_id = v_art1_id AND depot_id = v_depot_id;
  RETURN NEXT is(v_stock, 7::numeric, 'art1 stock adjusted to 7');

  SELECT sum(quantite) INTO v_stock FROM stock.mouvement WHERE article_id = v_art2_id AND depot_id = v_depot_id;
  RETURN NEXT is(v_stock, 5::numeric, 'art2 stock unchanged');

  -- Test 2: inventaire sans écart
  v_result := stock.post_inventaire_valider(jsonb_build_object(
    'p_depot_id', v_depot_id,
    'qty_' || v_art1_id, '7',
    'qty_' || v_art2_id, '5'
  ));
  RETURN NEXT ok(v_result LIKE '%Stock conforme%', 'no adjustment needed');

  -- Test 3: inventaire avec augmentation
  v_result := stock.post_inventaire_valider(jsonb_build_object(
    'p_depot_id', v_depot_id,
    'qty_' || v_art2_id, '8'
  ));
  SELECT sum(quantite) INTO v_stock FROM stock.mouvement WHERE article_id = v_art2_id AND depot_id = v_depot_id;
  RETURN NEXT is(v_stock, 8::numeric, 'art2 stock increased to 8');

  -- Test 4: dépôt invalide
  v_result := stock.post_inventaire_valider('{"p_depot_id": 99999}'::jsonb);
  RETURN NEXT ok(v_result LIKE '%Dépôt introuvable%', 'invalid depot blocked');

  -- Cleanup
  DELETE FROM stock.mouvement WHERE article_id IN (v_art1_id, v_art2_id);
  DELETE FROM stock.article WHERE id IN (v_art1_id, v_art2_id);
  DELETE FROM stock.depot WHERE id = v_depot_id;
  DELETE FROM crm.client WHERE id = v_fournisseur_id;
END;
$function$;
COMMENT ON FUNCTION stock_ut.test_post_inventaire_valider() IS 'Test post_inventaire_valider — batch inventory adjustments';

GRANT USAGE ON SCHEMA stock_ut TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA stock_ut TO web_anon;

-- Schema: stock_qa
CREATE SCHEMA IF NOT EXISTS stock_qa;

CREATE OR REPLACE FUNCTION stock_qa.clean()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);
  DELETE FROM stock.mouvement WHERE tenant_id = 'dev';
  DELETE FROM stock.article WHERE tenant_id = 'dev';
  DELETE FROM stock.depot WHERE tenant_id = 'dev';
  -- Clean fournisseurs créés par seed
  DELETE FROM crm.client WHERE name IN ('Scierie du Jura', 'Quincaillerie Pro') AND tenant_id = 'dev';
END;
$function$;
COMMENT ON FUNCTION stock_qa.clean() IS 'Nettoyer les données de seed stock';

CREATE OR REPLACE FUNCTION stock_qa.seed()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_dep_atelier int;
  v_dep_vehicule int;
  v_chene int;
  v_douglas int;
  v_vis int;
  v_tirefond int;
  v_osb int;
  v_laine int;
  v_huile int;
  v_colle int;
  v_equerre int;
  v_pointe int;
  v_fournisseur_bois int;
  v_fournisseur_quincaillerie int;
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);

  -- Fournisseurs CRM (réutilise ou crée)
  SELECT id INTO v_fournisseur_bois FROM crm.client WHERE name = 'Scierie du Jura' AND tenant_id = 'dev';
  IF NOT FOUND THEN
    INSERT INTO crm.client (name, type, city, tenant_id)
    VALUES ('Scierie du Jura', 'company', 'Arbois', 'dev')
    RETURNING id INTO v_fournisseur_bois;
  END IF;

  SELECT id INTO v_fournisseur_quincaillerie FROM crm.client WHERE name = 'Quincaillerie Pro' AND tenant_id = 'dev';
  IF NOT FOUND THEN
    INSERT INTO crm.client (name, type, city, tenant_id)
    VALUES ('Quincaillerie Pro', 'company', 'Besançon', 'dev')
    RETURNING id INTO v_fournisseur_quincaillerie;
  END IF;

  -- Dépôts
  INSERT INTO stock.depot (nom, type, adresse, tenant_id) VALUES
    ('Atelier principal', 'atelier', '12 rue des Chênes, Lons-le-Saunier', 'dev') RETURNING id INTO v_dep_atelier;
  INSERT INTO stock.depot (nom, type, tenant_id) VALUES
    ('Véhicule utilitaire', 'vehicule', 'dev') RETURNING id INTO v_dep_vehicule;
  INSERT INTO stock.depot (nom, type, adresse, tenant_id) VALUES
    ('Chantier Martin', 'chantier', '8 impasse des Tilleuls, Poligny', 'dev');

  -- Articles
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, seuil_mini, fournisseur_id, tenant_id) VALUES
    ('BOIS-CHENE-27', 'Chêne massif 27mm', 'bois', 'm3', 850.00, 850.0000, 2, v_fournisseur_bois, 'dev') RETURNING id INTO v_chene;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, seuil_mini, fournisseur_id, tenant_id) VALUES
    ('BOIS-DOUG-45', 'Douglas 45mm', 'bois', 'm3', 420.00, 420.0000, 3, v_fournisseur_bois, 'dev') RETURNING id INTO v_douglas;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, seuil_mini, fournisseur_id, tenant_id) VALUES
    ('QUINC-VIS-5x50', 'Vis inox 5x50 (boîte 200)', 'quincaillerie', 'u', 18.50, 18.5000, 5, v_fournisseur_quincaillerie, 'dev') RETURNING id INTO v_vis;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, seuil_mini, fournisseur_id, tenant_id) VALUES
    ('QUINC-TIRE-8x80', 'Tirefond 8x80 (boîte 50)', 'quincaillerie', 'u', 24.00, 24.0000, 3, v_fournisseur_quincaillerie, 'dev') RETURNING id INTO v_tirefond;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, seuil_mini, fournisseur_id, tenant_id) VALUES
    ('PAN-OSB-18', 'OSB 18mm 2500x1250', 'panneau', 'u', 32.00, 32.0000, 10, v_fournisseur_bois, 'dev') RETURNING id INTO v_osb;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, seuil_mini, fournisseur_id, tenant_id) VALUES
    ('ISOL-LAINE-60', 'Laine de bois 60mm', 'isolant', 'm2', 8.50, 8.5000, 20, v_fournisseur_bois, 'dev') RETURNING id INTO v_laine;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, fournisseur_id, tenant_id) VALUES
    ('FIN-HUILE-LIN', 'Huile de lin 5L', 'finition', 'u', 35.00, 35.0000, v_fournisseur_quincaillerie, 'dev') RETURNING id INTO v_huile;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, fournisseur_id, tenant_id) VALUES
    ('FIN-COLLE-PU', 'Colle PU D4 750g', 'finition', 'u', 22.00, 22.0000, v_fournisseur_quincaillerie, 'dev') RETURNING id INTO v_colle;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, seuil_mini, fournisseur_id, tenant_id) VALUES
    ('QUINC-EQUER-90', 'Équerre 90° renforcée', 'quincaillerie', 'u', 3.50, 3.5000, 20, v_fournisseur_quincaillerie, 'dev') RETURNING id INTO v_equerre;
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, pmp, fournisseur_id, tenant_id) VALUES
    ('QUINC-POINT-70', 'Pointe tête plate 70mm (kg)', 'quincaillerie', 'kg', 8.00, 8.0000, v_fournisseur_quincaillerie, 'dev') RETURNING id INTO v_pointe;

  -- Mouvements: entrées fournisseur
  INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, tenant_id) VALUES
    (v_chene, v_dep_atelier, 'entree', 5, 850.00, 'BL-2026-001', 'dev'),
    (v_douglas, v_dep_atelier, 'entree', 8, 420.00, 'BL-2026-001', 'dev'),
    (v_vis, v_dep_atelier, 'entree', 20, 18.50, 'BL-2026-002', 'dev'),
    (v_tirefond, v_dep_atelier, 'entree', 10, 24.00, 'BL-2026-002', 'dev'),
    (v_osb, v_dep_atelier, 'entree', 30, 32.00, 'BL-2026-003', 'dev'),
    (v_laine, v_dep_atelier, 'entree', 50, 8.50, 'BL-2026-003', 'dev'),
    (v_huile, v_dep_atelier, 'entree', 6, 35.00, 'BL-2026-004', 'dev'),
    (v_colle, v_dep_atelier, 'entree', 8, 22.00, 'BL-2026-004', 'dev'),
    (v_equerre, v_dep_atelier, 'entree', 50, 3.50, 'BL-2026-005', 'dev'),
    (v_pointe, v_dep_atelier, 'entree', 10, 8.00, 'BL-2026-005', 'dev');

  -- Sorties chantier
  INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, tenant_id) VALUES
    (v_chene, v_dep_atelier, 'sortie', -2, 850.00, 'CHANTIER-MARTIN', 'dev'),
    (v_osb, v_dep_atelier, 'sortie', -8, 32.00, 'CHANTIER-MARTIN', 'dev'),
    (v_vis, v_dep_atelier, 'sortie', -5, 18.50, 'CHANTIER-MARTIN', 'dev');

  -- Transfert atelier -> véhicule
  INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, depot_destination_id, reference, tenant_id) VALUES
    (v_equerre, v_dep_atelier, 'transfert', -15, 3.50, v_dep_vehicule, 'TRANSFERT-001', 'dev'),
    (v_equerre, v_dep_vehicule, 'transfert', 15, 3.50, v_dep_atelier, 'TRANSFERT-001', 'dev');

  -- Laine de bois: sortie pour mettre sous seuil (alerte)
  INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, tenant_id) VALUES
    (v_laine, v_dep_atelier, 'sortie', -35, 8.50, 'CHANTIER-DUPONT', 'dev');

  -- Inventaire: ajustement pointes (pertes constatées)
  INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, reference, tenant_id) VALUES
    (v_pointe, v_dep_atelier, 'inventaire', -2, 'INV-20260310', 'dev');

  -- 2e entrée douglas à prix différent (PMP recalc demo)
  INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, tenant_id) VALUES
    (v_douglas, v_dep_atelier, 'entree', 4, 450.00, 'BL-2026-006', 'dev');
END;
$function$;
COMMENT ON FUNCTION stock_qa.seed() IS 'Seed données démo artisan charpentier: 3 dépôts, 10 articles, ~18 mouvements (entrées, sorties, transfert, inventaire), 1 alerte';

GRANT USAGE ON SCHEMA stock_qa TO web_anon;
